import re
import sys
from zeep import Client
from zeep.exceptions import Fault, TransportError
from lxml import etree


def validate_policy_number(policy_number: str) -> str:
    """Validate and sanitize policy number input."""
    if not policy_number or not isinstance(policy_number, str):
        raise ValueError("Policy number must be a non-empty string")
    
    policy_number = policy_number.strip()
    
    # Policy numbers should be alphanumeric with optional hyphens
    if not re.match(r'^[A-Za-z0-9\-]{1,50}$', policy_number):
        raise ValueError(
            "Policy number must contain only alphanumeric characters and hyphens, "
            "and be between 1 and 50 characters"
        )
    
    return policy_number


def validate_customer_name(customer_name: str) -> str:
    """Validate and sanitize customer name input."""
    if not customer_name or not isinstance(customer_name, str):
        raise ValueError("Customer name must be a non-empty string")
    
    customer_name = customer_name.strip()
    
    if len(customer_name) > 200:
        raise ValueError("Customer name must be 200 characters or fewer")
    
    # Allow letters, spaces, hyphens, apostrophes, and periods (common in names)
    if not re.match(r"^[A-Za-z\s\-'.]+$", customer_name):
        raise ValueError(
            "Customer name must contain only letters, spaces, hyphens, "
            "apostrophes, and periods"
        )
    
    return customer_name


def escape_xml_characters(value: str) -> str:
    """
    Escape XML special characters to prevent XML injection.
    This is a defense-in-depth measure; zeep handles parameterization,
    but we escape as an additional safety layer.
    """
    # Replace XML special characters with their entity references
    value = value.replace("&", "&amp;")
    value = value.replace("<", "&lt;")
    value = value.replace(">", "&gt;")
    value = value.replace('"', "&quot;")
    value = value.replace("'", "&apos;")
    return value


def contains_xml_injection_patterns(value: str) -> bool:
    """Check if the input contains common XML/SOAP injection patterns."""
    dangerous_patterns = [
        r'<\s*!\s*\[CDATA\[',       # CDATA sections
        r'<\s*!\s*ENTITY',           # Entity declarations
        r'<\s*!\s*DOCTYPE',          # DOCTYPE declarations
        r'<\s*\?xml',               # XML processing instructions
        r'<\s*/?\s*soap:',          # SOAP elements
        r'<\s*/?\s*soapenv:',       # SOAP envelope elements
        r'<\s*/?\s*wsse:',          # WS-Security elements
        r'<\s*script',              # Script tags
        r'xmlns\s*[:=]',           # Namespace declarations
        r'<\s*/?\s*[a-zA-Z]+:',    # Any namespaced XML elements
        r'&#x?[0-9a-fA-F]+;',     # Character references (numeric entities)
        r']]>',                     # CDATA closing
    ]
    
    for pattern in dangerous_patterns:
        if re.search(pattern, value, re.IGNORECASE):
            return True
    return False


def sanitize_input(value: str, field_name: str) -> str:
    """
    Full sanitization pipeline for user input before passing to SOAP client.
    """
    if contains_xml_injection_patterns(value):
        raise ValueError(
            f"Invalid characters detected in {field_name}. "
            f"Input must not contain XML markup or special sequences."
        )
    
    # Apply XML character escaping as defense-in-depth
    sanitized = escape_xml_characters(value)
    
    return sanitized


def create_soap_client(wsdl_url: str) -> Client:
    """Create a zeep SOAP client with secure settings."""
    from zeep.settings import Settings
    
    # Disable XML entity expansion to prevent XXE attacks
    settings = Settings(
        strict=True,
        xml_huge_tree=False,  # Prevent processing of very large XML trees
    )
    
    # Configure custom XML parser that disables dangerous features
    parser = etree.XMLParser(
        resolve_entities=False,  # Prevent XXE
        no_network=True,         # Prevent network-based XXE
        dtd_validation=False,
        load_dtd=False,
    )
    
    client = Client(wsdl_url, settings=settings)
    return client


def lookup_policy(wsdl_url: str, policy_number: str, customer_name: str) -> dict:
    """
    Look up an insurance policy using the SOAP service.
    
    Uses zeep's parameterized approach to build SOAP messages safely,
    with additional input validation and sanitization.
    """
    # Step 1: Validate inputs against expected formats
    policy_number = validate_policy_number(policy_number)
    customer_name = validate_customer_name(customer_name)
    
    # Step 2: Check for XML injection patterns
    policy_number = sanitize_input(policy_number, "policy number")
    customer_name = sanitize_input(customer_name, "customer name")
    
    # Step 3: Create SOAP client
    client = create_soap_client(wsdl_url)
    
    # Step 4: Use zeep's parameterized service call
    # zeep handles XML serialization safely - values are passed as parameters,
    # NOT concatenated into XML strings. This is the primary defense against
    # SOAP XML injection.
    try:
        response = client.service.LookupPolicy(
            PolicyNumber=policy_number,
            CustomerName=customer_name
        )
        
        # Convert zeep response to a dictionary
        if response is not None:
            return {
                "status": "success",
                "data": serialize_response(response)
            }
        else:
            return {
                "status": "not_found",
                "message": "No policy found matching the provided criteria"
            }
            
    except Fault as e:
        return {
            "status": "error",
            "message": f"SOAP Fault: {e.message}",
            "code": getattr(e, 'code', None)
        }
    except TransportError as e:
        return {
            "status": "error",
            "message": f"Transport error: {str(e)}"
        }
    except Exception as e:
        return {
            "status": "error",
            "message": f"Unexpected error: {str(e)}"
        }


